const fs = require('fs');
const path = require('path');
const vaultPath = 'C:/Users/manaz/Desktop/JobFilter/JobFilterV1/Obsidian_Memory/Obsidian_Vault';
const statePath = path.join(vaultPath, 'JobFilter', 'Agent Runs', '.waitlist-state.json');
const body = $input.first().json || {};
const count = Number(body.count ?? body.total ?? 0);
const milestones = [10, 25, 50, 100, 250, 500, 1000, 2500, 5000];
let prev = { lastCount: 0, hit: [] };
if (fs.existsSync(statePath)) { try { prev = JSON.parse(fs.readFileSync(statePath, 'utf-8')); } catch {} }
const newlyHit = milestones.filter(m => count >= m && !(prev.hit || []).includes(m));
const state = { lastCount: count, hit: Array.from(new Set([...(prev.hit || []), ...newlyHit])).sort((a,b)=>a-b), updated_at: new Date().toISOString() };
fs.mkdirSync(path.dirname(statePath), { recursive: true });
fs.writeFileSync(statePath, JSON.stringify(state, null, 2));
return [{ json: { count, newlyHit, hitCount: newlyHit.length, hasMilestone: newlyHit.length > 0, prevCount: prev.lastCount || 0, delta: count - (prev.lastCount || 0) } }];
